function lightenColor(hex, amount) {
  const num = parseInt(hex.replace("#", ""), 16);
  const r = Math.min(255, (num >> 16) + amount);
  const g = Math.min(255, ((num >> 8) & 0x00ff) + amount);
  const b = Math.min(255, (num & 0x0000ff) + amount);
  return `#${(1 << 24 | r << 16 | g << 8 | b).toString(16).slice(1)}`;
}

function wordWrap(text, maxChars) {
  const words = text.split(' ');
  const lines = [];
  let current = '';
  for (const word of words) {
    if (current && (current + ' ' + word).length > maxChars) {
      lines.push(current);
      current = word;
    } else {
      current = current ? current + ' ' + word : word;
    }
  }
  if (current) lines.push(current);
  return lines;
}

function generateStrengthValues(numCards) {
  const base = Array(Math.floor(numCards / 5)).fill(null).flatMap(() => [1, 2, 3, 4, 5]);
  const remainder = numCards % 5;
  for (let i = 0; i < remainder; i++) base.push(Math.floor(Math.random() * 5) + 1);
  for (let i = base.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [base[i], base[j]] = [base[j], base[i]];
  }
  return base;
}

const emptyCard = () => ({
  name: "", level: "", photo: null, specialAbility: "",
  stats: ["", ""], teamIndex: 0, photoOffsetY: 0, photoZoom: 1,
});

export default function App() {
  const [teams, setTeams] = useState(DEFAULT_TEAMS);
  const [cards, setCards] = useState([emptyCard()]);
  const [activeCard, setActiveCard] = useState(0);
  const [activeTab, setActiveTab] = useState("cards");
  const [numDecks, setNumDecks] = useState(5);
  const [exporting, setExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState("");
  const [showBack, setShowBack] = useState(false);
  const fileRef = useRef(null);

  const card = cards[activeCard] || emptyCard();
  const team = teams[card.teamIndex] || teams[0];

  const updateCard = (field, value) => {
    setCards(prev => {
      const next = [...prev];
      next[activeCard] = { ...next[activeCard], [field]: value };
      return next;
    });
  };

  const updateStat = (idx, value) => {
    setCards(prev => {
      const next = [...prev];
      const stats = [...next[activeCard].stats];
      stats[idx] = value;
      next[activeCard] = { ...next[activeCard], stats };
      return next;
    });
  };

  const updateTeam = (idx, field, value) => {
    setTeams(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], [field]: value };
      return next;
    });
  };

  const addCard = () => {
    setCards(prev => [...prev, emptyCard()]);
    setActiveCard(cards.length);
  };

  const removeCard = (idx) => {
    if (cards.length <= 1) return;
    setCards(prev => prev.filter((_, i) => i !== idx));
    setActiveCard(Math.max(0, activeCard >= idx ? activeCard - 1 : activeCard));
  };

  const duplicateCard = (idx) => {
    const copy = { ...cards[idx], stats: [...cards[idx].stats] };
    setCards(prev => [...prev.slice(0, idx + 1), copy, ...prev.slice(idx + 1)]);
    setActiveCard(idx + 1);
  };

  const handlePhoto = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => updateCard("photo", ev.target.result);
    reader.readAsDataURL(file);
  };

  const escXml = (s) => String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");

  const buildFrontSvgString = (data, teamObj, index, totalCards) => {
    const p = teamObj.primary;
    const a = teamObj.accent;
    const lp = lightenColor(p, 30);
    const lp2 = lightenColor(p, 40);
    const pillW = Math.max(teamObj.name.length * 9 + 24, 90);
    const name = escXml(data.name || "Name eingeben");
    const level = escXml(data.level || "?");
    const ability = data.specialAbility ? escXml(data.specialAbility) : "...";
    const num = `#${String(index + 1).padStart(2, "0")} / ${totalCards}`;

    const photoBlock = `<rect x="28" y="138" width="${PX_W - 56}" height="240" rx="6" fill="${data.photo ? '#E0D8C8' : '#D5CCBA'}"/>`;

    const statsBlock = CATEGORIES.map((cat, i) => {
      const y = 530 + i * 50;
      const val = data.stats[i] || "\u2014";
      const bg = i % 2 === 0 ? `<rect x="22" y="${y - 4}" width="${PX_W - 44}" height="36" rx="4" fill="${p}" opacity="0.07"/>` : "";
      let valBlock;
      if (i === 0) {
        valBlock = `<text x="${PX_W - 30}" y="${y + 18}" font-size="12" fill="${lp}" text-anchor="end" font-weight="600" font-family="Trebuchet MS,sans-serif">${escXml(val)}</text>`;
      } else {
        const valLines = wordWrap(val, 30);
        valBlock = valLines.map((vl, vi) =>
          `<text x="60" y="${y + 18 + vi * 18}" font-size="12" fill="${lp}" font-weight="600" font-family="Trebuchet MS,sans-serif">${escXml(vl)}</text>`
        ).join("\n");
      }
      return `${bg}
        <circle cx="40" cy="${y + 14}" r="12" fill="${a}"/>
        <text x="40" y="${y + 18}" font-size="11" font-weight="800" fill="${p}" text-anchor="middle" font-family="Trebuchet MS,sans-serif">${CAT_ICONS[i]}</text>
        <text x="60" y="${y + 18}" font-size="13" font-weight="700" fill="${p}" font-family="Trebuchet MS,sans-serif">${escXml(cat)}</text>
        ${valBlock}`;
    }).join("\n");

    const abilityWrapped = wordWrap(ability || "...", 48).slice(0, 4);
    const abilityBlock = abilityWrapped.map((line, i) => {
      const text = data.specialAbility ? (i === 0 ? `"${line}` : i === abilityWrapped.length - 1 ? `${line}"` : line) : line;
      return `<text x="34" y="${432 + i * 18}" font-size="12" fill="#E8E4D8" font-style="italic" font-family="Trebuchet MS,sans-serif">${escXml(text)}</text>`;
    }).join("\n");

    return `<svg width="${PX_W}" height="${PX_H}" viewBox="0 0 ${PX_W} ${PX_H}" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <clipPath id="card-${index}"><rect x="0" y="0" width="${PX_W}" height="${PX_H}" rx="16"/></clipPath>
        <clipPath id="photo-${index}"><rect x="28" y="138" width="${PX_W - 56}" height="240" rx="6"/></clipPath>
        <linearGradient id="border-${index}" x1="0" y1="0" x2="1" y2="1">
          <stop offset="0%" stop-color="${a}"/><stop offset="50%" stop-color="#F5C96A"/><stop offset="100%" stop-color="${a}"/>
        </linearGradient>
        <linearGradient id="header-${index}" x1="0" y1="0" x2="1" y2="0">
          <stop offset="0%" stop-color="${p}"/><stop offset="100%" stop-color="${lp}"/>
        </linearGradient>
      </defs>
      <rect width="${PX_W}" height="${PX_H}" rx="16" fill="url(#border-${index})"/>
      <rect x="6" y="6" width="${PX_W - 12}" height="${PX_H - 12}" rx="12" fill="${p}"/>
      <rect x="14" y="14" width="${PX_W - 28}" height="${PX_H - 28}" rx="8" fill="#F7F3E8"/>
      <rect x="14" y="14" width="${PX_W - 28}" height="108" rx="8" fill="url(#header-${index})" clip-path="url(#card-${index})"/>
      <rect x="14" y="100" width="${PX_W - 28}" height="22" fill="url(#header-${index})"/>
      <text x="28" y="56" font-size="26" font-weight="800" fill="#FFF" letter-spacing="0.5" font-family="Trebuchet MS,sans-serif">${name}</text>
      <rect x="28" y="68" width="${pillW}" height="26" rx="13" fill="${a}"/>
      <text x="${28 + pillW / 2}" y="86" font-size="11" font-weight="700" fill="${p}" text-anchor="middle" letter-spacing="0.8" font-family="Trebuchet MS,sans-serif">${escXml(teamObj.name.toUpperCase())}</text>
      <circle cx="${PX_W - 52}" cy="56" r="32" fill="${a}" stroke="#F5C96A" stroke-width="2.5"/>
      <text x="${PX_W - 52}" y="48" font-size="11" font-weight="700" fill="${p}" text-anchor="middle" font-family="Trebuchet MS,sans-serif">LV</text>
      <text x="${PX_W - 52}" y="72" font-size="24" font-weight="800" fill="${p}" text-anchor="middle" font-family="Trebuchet MS,sans-serif">${level}</text>
      <text x="${PX_W - 28}" y="118" font-size="11" fill="${lp2}" text-anchor="end" font-weight="600" font-family="Trebuchet MS,sans-serif">${num}</text>
      <rect x="22" y="132" width="${PX_W - 44}" height="252" rx="8" fill="url(#border-${index})"/>
      <rect x="28" y="138" width="${PX_W - 56}" height="240" rx="6" fill="#E0D8C8"/>
      ${photoBlock}
      <rect x="22" y="394" width="${PX_W - 44}" height="100" rx="6" fill="${p}"/>
      <text x="34" y="412" font-size="9" fill="${a}" letter-spacing="1.5" font-weight="700" font-family="Trebuchet MS,sans-serif">BESCHREIBUNG</text>
      ${abilityBlock}
      <text x="28" y="518" font-size="9" fill="${p}" letter-spacing="1.5" font-weight="700" font-family="Trebuchet MS,sans-serif">STECKBRIEF</text>
      ${statsBlock}
      <rect x="14" y="${PX_H - 32}" width="${PX_W - 28}" height="18" fill="${p}" clip-path="url(#card-${index})"/>
      <text x="${PX_W / 2}" y="${PX_H - 19}" font-size="9" fill="${a}" text-anchor="middle" letter-spacing="3" font-weight="700" font-family="Trebuchet MS,sans-serif">FREUNDSCHAFT.</text>
    </svg>`;
  };

  const buildBackSvgString = (deckIndex, cardIndex, strengthValue, teamObj) => {
    const p = teamObj.primary;
    const a = teamObj.accent;
    const idx = `back-${deckIndex}-${cardIndex}`;
    const logoSize = 180;
    const stars = "\u2605".repeat(strengthValue) + "\u2606".repeat(5 - strengthValue);

    return `<svg width="${PX_W}" height="${PX_H}" viewBox="0 0 ${PX_W} ${PX_H}" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <linearGradient id="bb-${idx}" x1="0" y1="0" x2="1" y2="1">
          <stop offset="0%" stop-color="${a}"/><stop offset="50%" stop-color="#F5C96A"/><stop offset="100%" stop-color="${a}"/>
        </linearGradient>
        <clipPath id="logoClip-${idx}">
          <circle cx="${PX_W / 2}" cy="${PX_H / 2 - 60}" r="${logoSize / 2}"/>
        </clipPath>
      </defs>
      <rect width="${PX_W}" height="${PX_H}" rx="16" fill="url(#bb-${idx})"/>
      <rect x="6" y="6" width="${PX_W - 12}" height="${PX_H - 12}" rx="12" fill="${p}"/>
      <circle cx="${PX_W / 2}" cy="${PX_H / 2 - 60}" r="${logoSize / 2 + 12}" fill="none" stroke="${a}" stroke-width="1" opacity="0.2"/>
      <circle cx="${PX_W / 2}" cy="${PX_H / 2 - 60}" r="${logoSize / 2}" fill="${a}" opacity="0.15"/>
      <text x="${PX_W / 2}" y="${PX_H / 2 + 60}" font-size="28" fill="${a}" text-anchor="middle" letter-spacing="4" font-family="Trebuchet MS,sans-serif">${stars}</text>
      <text x="${PX_W / 2}" y="${PX_H / 2 + 85}" font-size="11" fill="${a}" text-anchor="middle" letter-spacing="1" opacity="0.7" font-family="Trebuchet MS,sans-serif">ST\u00c4RKE</text>
      <text x="${PX_W / 2}" y="${PX_H - 40}" font-size="14" font-weight="600" fill="${a}" text-anchor="middle" letter-spacing="2" font-family="Trebuchet MS,sans-serif">27.04.2026</text>
    </svg>`;
  };

  const svgStringToCanvas = (svgString, w, h) => {
    return new Promise((resolve, reject) => {
      const svgB64 = "data:image/svg+xml;base64," + btoa(unescape(encodeURIComponent(svgString)));
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement("canvas");
        canvas.width = w * 2;
        canvas.height = h * 2;
        const ctx = canvas.getContext("2d");
        ctx.scale(2, 2);
        ctx.drawImage(img, 0, 0, w, h);
        resolve(canvas);
      };
      img.onerror = (e) => reject(new Error("SVG render failed"));
      img.src = svgB64;
    });
  };

  const loadImage = (src) => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => resolve(img);
      img.onerror = () => reject(new Error("Image load failed"));
      img.src = src;
    });
  };

  const renderFrontToCanvas = async (data, teamObj, index, totalCards) => {
    const svgStr = buildFrontSvgString(data, teamObj, index, totalCards);
    const canvas = await svgStringToCanvas(svgStr, PX_W, PX_H);

    if (data.photo) {
      try {
        const photoImg = await loadImage(data.photo);
        const ctx = canvas.getContext("2d");
        // Canvas has scale(2,2) still active, so use SVG coordinates directly
        const px = 28, py = 138, pw = PX_W - 56, ph = 240;

        ctx.save();
        ctx.beginPath();
        ctx.roundRect(px, py, pw, ph, 6);
        ctx.clip();

        const imgRatio = photoImg.width / photoImg.height;
        const boxRatio = pw / ph;
        let sx, sy, sw, sh;
        if (imgRatio > boxRatio) {
          sh = photoImg.height;
          sw = sh * boxRatio;
          sx = (photoImg.width - sw) / 2;
          sy = 0;
        } else {
          sw = photoImg.width;
          sh = sw / boxRatio;
          sx = 0;
          sy = (photoImg.height - sh) / 2;
        }
        ctx.drawImage(photoImg, sx, sy, sw, sh, px, py, pw, ph);
        ctx.restore();
      } catch (e) {
        console.warn("Photo render failed:", e);
      }
    }

    return canvas;
  };

  const renderBackToCanvas = async (deckIndex, cardIndex, strengthValue, teamObj) => {
    const svgStr = buildBackSvgString(deckIndex, cardIndex, strengthValue, teamObj);
    const canvas = await svgStringToCanvas(svgStr, PX_W, PX_H);

    try {
      const logoImg = await loadImage(LOGO_B64);
      const ctx = canvas.getContext("2d");
      // Canvas has scale(2,2) still active, so use SVG coordinates directly
      const logoSize = 180;
      const cx = PX_W / 2;
      const cy = PX_H / 2 - 60;
      const lx = cx - logoSize / 2;
      const ly = cy - logoSize / 2;

      ctx.save();
      ctx.beginPath();
      ctx.arc(cx, cy, logoSize / 2, 0, Math.PI * 2);
      ctx.clip();
      ctx.drawImage(logoImg, lx, ly, logoSize, logoSize);
      ctx.restore();
    } catch (e) {
      console.warn("Logo render failed:", e);
    }

    return canvas;
  };

  const loadJsPDF = () => Promise.resolve(jsPDF);

  const exportPDF = async () => {
    setExporting(true);
    setExportProgress("PDF-Bibliothek wird geladen...");

    try {
      const jsPDF = await loadJsPDF();

      const marginX = 10;
      const marginY = 10;
      const gap = 3;
      const cols = Math.floor((210 - 2 * marginX + gap) / (CARD_W + gap));
      const rows = Math.floor((297 - 2 * marginY + gap) / (CARD_H + gap));
      const cardsPerPage = cols * rows;

      // Pre-render all front canvases
      setExportProgress("Vorderseiten werden gerendert...");
      const frontCanvases = [];
      for (let i = 0; i < cards.length; i++) {
        const t = teams[cards[i].teamIndex] || teams[0];
        const canvas = await renderFrontToCanvas(cards[i], t, i, cards.length);
        frontCanvases.push(canvas.toDataURL("image/png"));
        await new Promise(r => setTimeout(r, 30));
      }

      for (let deck = 0; deck < numDecks; deck++) {
        setExportProgress(`Deck ${deck + 1}/${numDecks} wird erstellt...`);
        const pdf = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4" });
        const strengths = generateStrengthValues(cards.length);

        // Front pages
        for (let i = 0; i < cards.length; i++) {
          if (i > 0 && i % cardsPerPage === 0) pdf.addPage();
          const pos = i % cardsPerPage;
          const col = pos % cols;
          const row = Math.floor(pos / cols);
          const x = marginX + col * (CARD_W + gap);
          const y = marginY + row * (CARD_H + gap);
          pdf.addImage(frontCanvases[i], "PNG", x, y, CARD_W, CARD_H);
        }

        // Back pages
        for (let i = 0; i < cards.length; i++) {
          setExportProgress(`Deck ${deck + 1}/${numDecks} — Rückseite ${i + 1}/${cards.length}`);
          if (i % cardsPerPage === 0) pdf.addPage();
          const pos = i % cardsPerPage;
          const col = (cols - 1) - (pos % cols);
          const row = Math.floor(pos / cols);
          const x = marginX + col * (CARD_W + gap);
          const y = marginY + row * (CARD_H + gap);

          const t = teams[cards[i].teamIndex] || teams[0];
          const canvas = await renderBackToCanvas(deck, i, strengths[i], t);
          pdf.addImage(canvas.toDataURL("image/png"), "PNG", x, y, CARD_W, CARD_H);
          await new Promise(r => setTimeout(r, 30));
        }

        pdf.save(`Freundschaft_Deck_${deck + 1}.pdf`);
        await new Promise(r => setTimeout(r, 200));
      }

      setExportProgress("Fertig!");
      await new Promise(r => setTimeout(r, 1500));
    } catch (err) {
      console.error("Export error:", err);
      setExportProgress("Fehler: " + (err.message || String(err)));
      await new Promise(r => setTimeout(r, 4000));
    }

    setExporting(false);
    setExportProgress("");
  };

  const inputStyle = {
    width: "100%",
    padding: "8px 12px",
    fontSize: "14px",
    border: "0.5px solid #d0d0d0",
    borderRadius: "8px",
    background: "#ffffff",
    color: "#1a1a1a",
    boxSizing: "border-box",
  };

  const labelStyle = {
    fontSize: "12px",
    fontWeight: 500,
    color: "#666666",
    marginBottom: "4px",
    display: "block",
  };

  return (
    <div style={{ padding: "1rem 0" }}>
      <div style={{
        display: "flex", alignItems: "center", gap: "12px",
        marginBottom: "1.5rem", borderBottom: "0.5px solid #e0e0e0",
        paddingBottom: "1rem",
      }}>
        <div style={{
          width: "40px", height: "40px", borderRadius: "50%",
          background: "#1B4332", display: "flex", alignItems: "center",
          justifyContent: "center", fontSize: "16px", fontWeight: 700, color: "#E8942E",
        }}>F.</div>
        <div>
          <div style={{ fontSize: "18px", fontWeight: 500, color: "#1a1a1a" }}>
            Freundschaft. Kartengenerator
          </div>
          <div style={{ fontSize: "13px", color: "#666666" }}>
            {cards.length} Karte{cards.length !== 1 ? "n" : ""} · {teams.filter(t => t.name !== `Team ${teams.indexOf(t) + 1}`).length || 6} Teams · {numDecks} Decks
          </div>
        </div>
      </div>

      {/* Tab navigation */}
      <div style={{ display: "flex", gap: "4px", marginBottom: "1.5rem" }}>
        {[
          { id: "cards", label: "Karten bearbeiten" },
          { id: "teams", label: "Teams & Farben" },
          { id: "export", label: "PDF Export" },
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            style={{
              padding: "8px 16px", fontSize: "13px", fontWeight: 500, cursor: "pointer",
              border: "0.5px solid #d0d0d0",
              borderRadius: "8px",
              background: activeTab === tab.id ? "#1a1a1a" : "transparent",
              color: activeTab === tab.id ? "#ffffff" : "#1a1a1a",
            }}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {activeTab === "teams" && (
        <div>
          <p style={{ fontSize: "14px", color: "#666666", marginBottom: "1rem" }}>
            Lege hier die 6 Team-Namen und Farben fest. Die Primärfarbe bestimmt Header, Banner und Textfarben. Die Akzentfarbe den Rahmen und Badges.
          </p>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: "12px" }}>
            {teams.map((t, i) => (
              <div key={i} style={{
                padding: "12px", borderRadius: "12px",
                border: "0.5px solid #e0e0e0",
                background: "#ffffff",
              }}>
                <label style={labelStyle}>Team {i + 1} — Name</label>
                <input
                  style={{ ...inputStyle, marginBottom: "8px" }}
                  value={t.name}
                  onChange={e => updateTeam(i, "name", e.target.value)}
                  placeholder={`Team ${i + 1}`}
                />
                <div style={{ display: "flex", gap: "8px" }}>
                  <div style={{ flex: 1 }}>
                    <label style={labelStyle}>Primärfarbe</label>
                    <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
                      <input
                        type="color" value={t.primary}
                        onChange={e => updateTeam(i, "primary", e.target.value)}
                        style={{ width: "32px", height: "32px", border: "none", cursor: "pointer", background: "none" }}
                      />
                      <input
                        style={{ ...inputStyle, fontFamily: "monospace", fontSize: "12px" }}
                        value={t.primary}
                        onChange={e => updateTeam(i, "primary", e.target.value)}
                      />
                    </div>
                  </div>
                  <div style={{ flex: 1 }}>
                    <label style={labelStyle}>Akzentfarbe</label>
                    <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
                      <input
                        type="color" value={t.accent}
                        onChange={e => updateTeam(i, "accent", e.target.value)}
                        style={{ width: "32px", height: "32px", border: "none", cursor: "pointer", background: "none" }}
                      />
                      <input
                        style={{ ...inputStyle, fontFamily: "monospace", fontSize: "12px" }}
                        value={t.accent}
                        onChange={e => updateTeam(i, "accent", e.target.value)}
                      />
                    </div>
                  </div>
                </div>
                {/* Mini preview */}
                <div style={{
                  marginTop: "8px", padding: "6px 10px", borderRadius: "6px",
                  background: t.primary, display: "flex", alignItems: "center", justifyContent: "space-between",
                }}>
                  <span style={{ fontSize: "11px", fontWeight: 700, color: "#FFF" }}>{t.name.toUpperCase()}</span>
                  <span style={{
                    fontSize: "10px", fontWeight: 700, color: t.primary,
                    background: t.accent, padding: "2px 8px", borderRadius: "8px",
                  }}>LV 5</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === "cards" && (
        <div style={{ display: "flex", gap: "1.5rem", flexWrap: "wrap" }}>
          {/* Left: Card list + form */}
          <div style={{ flex: "1 1 320px", minWidth: 0 }}>
            {/* Card list */}
            <div style={{
              display: "flex", flexWrap: "wrap", gap: "6px", marginBottom: "1rem",
            }}>
              {cards.map((c, i) => (
                <button
                  key={i}
                  onClick={() => setActiveCard(i)}
                  style={{
                    padding: "4px 10px", fontSize: "12px", fontWeight: 500, cursor: "pointer",
                    border: "0.5px solid #d0d0d0",
                    borderRadius: "8px",
                    background: activeCard === i
                      ? teams[c.teamIndex]?.primary || "#1B4332"
                      : "transparent",
                    color: activeCard === i ? "#FFF" : "#1a1a1a",
                  }}
                >
                  {c.name || `Karte ${i + 1}`}
                </button>
              ))}
              <button
                onClick={addCard}
                style={{
                  padding: "4px 12px", fontSize: "14px", cursor: "pointer",
                  border: "0.5px solid #d0d0d0",
                  borderRadius: "8px",
                  background: "transparent", color: "#666666",
                }}
              >
                + Neue Karte
              </button>
            </div>

            {/* Edit form */}
            <div style={{
              padding: "16px", borderRadius: "12px",
              border: "0.5px solid #e0e0e0",
              background: "#ffffff",
            }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "12px" }}>
                <span style={{ fontSize: "14px", fontWeight: 500 }}>Karte {activeCard + 1} bearbeiten</span>
                <div style={{ display: "flex", gap: "6px" }}>
                  <button
                    onClick={() => duplicateCard(activeCard)}
                    style={{
                      padding: "4px 10px", fontSize: "11px", cursor: "pointer",
                      border: "0.5px solid #d0d0d0",
                      borderRadius: "8px", background: "transparent",
                      color: "#666666",
                    }}
                  >
                    Duplizieren
                  </button>
                  <button
                    onClick={() => removeCard(activeCard)}
                    disabled={cards.length <= 1}
                    style={{
                      padding: "4px 10px", fontSize: "11px", cursor: "pointer",
                      border: "0.5px solid #e57373",
                      borderRadius: "8px", background: "transparent",
                      color: "#d32f2f",
                      opacity: cards.length <= 1 ? 0.4 : 1,
                    }}
                  >
                    Löschen
                  </button>
                </div>
              </div>

              <div style={{ display: "flex", gap: "12px", marginBottom: "12px" }}>
                <div style={{ flex: 2 }}>
                  <label style={labelStyle}>Name</label>
                  <input style={inputStyle} value={card.name} onChange={e => updateCard("name", e.target.value)} placeholder="Max Mustermann" />
                </div>
                <div style={{ flex: "0 0 70px" }}>
                  <label style={labelStyle}>Level</label>
                  <input style={{ ...inputStyle, textAlign: "center" }} value={card.level} onChange={e => updateCard("level", e.target.value)} placeholder="5" />
                </div>
              </div>

              <div style={{ marginBottom: "12px" }}>
                <label style={labelStyle}>Team</label>
                <div style={{ display: "flex", gap: "6px", flexWrap: "wrap" }}>
                  {teams.map((t, i) => (
                    <button
                      key={i}
                      onClick={() => updateCard("teamIndex", i)}
                      style={{
                        padding: "4px 12px", fontSize: "11px", fontWeight: 600,
                        cursor: "pointer", borderRadius: "8px",
                        border: card.teamIndex === i ? `2px solid ${t.accent}` : "0.5px solid #e0e0e0",
                        background: card.teamIndex === i ? t.primary : "transparent",
                        color: card.teamIndex === i ? "#FFF" : "#1a1a1a",
                      }}
                    >
                      {t.name}
                    </button>
                  ))}
                </div>
              </div>

              <div style={{ marginBottom: "12px" }}>
                <label style={labelStyle}>Foto</label>
                <input ref={fileRef} type="file" accept="image/*" onChange={handlePhoto} style={{ display: "none" }} />
                <button
                  onClick={() => fileRef.current?.click()}
                  style={{
                    padding: "8px 16px", fontSize: "13px", cursor: "pointer",
                    border: "0.5px solid #d0d0d0",
                    borderRadius: "8px", background: "transparent",
                    color: "#1a1a1a", width: "100%",
                  }}
                >
                  {card.photo ? "Foto ändern" : "Foto hochladen"}
                </button>
                {card.photo && (
                  <div style={{ marginTop: "8px" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "4px" }}>
                      <label style={{ ...labelStyle, marginBottom: 0, minWidth: "80px" }}>Verschieben</label>
                      <input
                        type="range" min="-120" max="120" value={card.photoOffsetY || 0}
                        onChange={e => updateCard("photoOffsetY", Number(e.target.value))}
                        style={{ flex: 1 }}
                      />
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                      <label style={{ ...labelStyle, marginBottom: 0, minWidth: "80px" }}>Zoom</label>
                      <input
                        type="range" min="1" max="2" step="0.05" value={card.photoZoom || 1}
                        onChange={e => updateCard("photoZoom", Number(e.target.value))}
                        style={{ flex: 1 }}
                      />
                    </div>
                  </div>
                )}
              </div>

              <div style={{ marginBottom: "12px" }}>
                <label style={labelStyle}>Beschreibung</label>
                <textarea style={{ ...inputStyle, minHeight: "60px", resize: "vertical" }} value={card.specialAbility} onChange={e => updateCard("specialAbility", e.target.value)} placeholder="Hier kann ein längerer Text stehen, z.B. eine lustige Beschreibung der Person..." />
              </div>

              {CATEGORIES.map((cat, i) => (
                <div key={cat} style={{ marginBottom: i < CATEGORIES.length - 1 ? "12px" : 0 }}>
                  <label style={labelStyle}>{CAT_ICONS[i]} {cat}</label>
                  <input style={inputStyle} value={card.stats[i]} onChange={e => updateStat(i, e.target.value)} placeholder={i === 0 ? "z.B. März 2023" : "z.B. Läuft bei mir."} />
                </div>
              ))}
            </div>
          </div>

          {/* Right: Preview */}
          <div style={{ flex: "0 0 auto", position: "sticky", top: "1rem", alignSelf: "flex-start" }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: "8px" }}>
              <span style={{ fontSize: "12px", color: "#666666", fontWeight: 500 }}>Vorschau</span>
              <div style={{ display: "flex", gap: "4px" }}>
                <button
                  onClick={() => setShowBack(false)}
                  style={{
                    padding: "3px 10px", fontSize: "11px", fontWeight: 500, cursor: "pointer",
                    border: "0.5px solid #d0d0d0",
                    borderRadius: "8px",
                    background: !showBack ? "#1a1a1a" : "transparent",
                    color: !showBack ? "#ffffff" : "#666666",
                  }}
                >
                  Vorderseite
                </button>
                <button
                  onClick={() => setShowBack(true)}
                  style={{
                    padding: "3px 10px", fontSize: "11px", fontWeight: 500, cursor: "pointer",
                    border: "0.5px solid #d0d0d0",
                    borderRadius: "8px",
                    background: showBack ? "#1a1a1a" : "transparent",
                    color: showBack ? "#ffffff" : "#666666",
                  }}
                >
                  Rückseite
                </button>
              </div>
            </div>
            <div style={{
              borderRadius: "12px",
              background: "#f5f3ee",
              padding: "20px",
              display: "inline-block",
            }}>
              <div style={{ transform: "scale(0.55)", transformOrigin: "top left", width: PX_W, height: PX_H }}>
                {showBack ? (
                  <CardBack deckIndex={0} cardIndex={activeCard} strengthValue={3} team={team} />
                ) : (
                  <CardPreview data={card} team={team} index={activeCard} totalCards={cards.length} />
                )}
              </div>
            </div>
            <div style={{ height: PX_H * 0.55 + 40 }} />
          </div>
        </div>
      )}

      {activeTab === "export" && (
        <div style={{
          padding: "20px", borderRadius: "12px",
          border: "0.5px solid #e0e0e0",
          background: "#ffffff",
          maxWidth: "480px",
        }}>
          <div style={{ marginBottom: "16px" }}>
            <label style={labelStyle}>Anzahl Decks</label>
            <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
              <input
                type="range" min="1" max="10" value={numDecks}
                onChange={e => setNumDecks(Number(e.target.value))}
                style={{ flex: 1 }}
              />
              <span style={{ fontSize: "18px", fontWeight: 500, minWidth: "28px" }}>{numDecks}</span>
            </div>
          </div>

          <div style={{
            padding: "12px 16px", borderRadius: "8px",
            background: "#f5f3ee", marginBottom: "16px",
            fontSize: "13px", color: "#666666", lineHeight: 1.7,
          }}>
            <strong style={{ color: "#1a1a1a" }}>{cards.length} Karten × {numDecks} Decks = {cards.length * numDecks} Karten total</strong><br />
            Jedes Deck enthält Vorder- und Rückseiten (mit zufälligen Stärkewerten)
            auf A4-Seiten im Format 63 × 88 mm. Die Rückseiten sind horizontal gespiegelt,
            damit sie beim beidseitigen Druck korrekt übereinanderliegen.
          </div>

          <button
            onClick={exportPDF}
            disabled={exporting || cards.length === 0}
            style={{
              width: "100%", padding: "12px", fontSize: "15px", fontWeight: 600,
              cursor: exporting ? "wait" : "pointer",
              border: "none", borderRadius: "8px",
              background: exporting ? "#f5f3ee" : "#1B4332",
              color: exporting ? "#666666" : "#E8942E",
            }}
          >
            {exporting ? exportProgress : `${numDecks} Deck${numDecks > 1 ? "s" : ""} als PDF exportieren`}
          </button>
        </div>
      )}
    </div>
  );
}
